import { GameConfig } from '../config/GameConfig';
import {
    CellData, GridPosition, GravityMove, SpawnedTile,
    SuperTileType, TileColor, TILE_COLOR_COUNT,
} from './Types';
import { MatchResolver } from './MatchResolver';

/**
 * Domain model of the blast‑game field (NxM grid of tiles).
 *
 * Responsibilities (SRP):
 *  • Store / query tile data
 *  • Find colour groups (delegates to MatchResolver)
 *  • Mutate the grid: remove, gravity, fill, shuffle, swap, place
 *  • Provide area queries (row / column / radius / all)
 *
 * All super‑tile *effect resolution* lives in SuperTileStrategy (Strategy pattern).
 * Zero Cocos dependencies — fully unit‑testable.
 */
export class FieldModel {

    private readonly rows: number;
    private readonly cols: number;
    private grid: (CellData | null)[][];

    constructor(rows: number = GameConfig.GRID_ROWS, cols: number = GameConfig.GRID_COLS) {
        this.rows = rows;
        this.cols = cols;
        this.grid = this.createEmpty();
        this.fillInitial();
    }

    // ── Accessors ─────────────────────────────────────────

    public getRows(): number { return this.rows; }
    public getCols(): number { return this.cols; }
    public getGrid(): (CellData | null)[][] { return this.grid; }

    public getCell(row: number, col: number): CellData | null {
        if (row < 0 || row >= this.rows || col < 0 || col >= this.cols) return null;
        return this.grid[row][col];
    }

    // ── Match queries (delegate to MatchResolver) ─────────

    public findGroup(row: number, col: number): GridPosition[] {
        return MatchResolver.findGroup(this.grid, row, col);
    }

    public hasValidMoves(): boolean {
        return MatchResolver.hasAnyValidGroup(this.grid, GameConfig.MIN_GROUP_SIZE);
    }

    // ── Mutations ─────────────────────────────────────────

    public removeTiles(positions: GridPosition[]): void {
        for (const p of positions) this.grid[p.row][p.col] = null;
    }

    public placeSuperTile(row: number, col: number, color: TileColor, superType: SuperTileType): void {
        this.grid[row][col] = { color, superType };
    }

    /** Compact non‑null cells downward in every column (row 0 = bottom). */
    public applyGravity(): GravityMove[] {
        const moves: GravityMove[] = [];

        for (let c = 0; c < this.cols; c++) {
            let write = 0;
            for (let read = 0; read < this.rows; read++) {
                const cell = this.grid[read][c];
                if (cell !== null) {
                    if (read !== write) {
                        moves.push({ from: { row: read, col: c }, to: { row: write, col: c }, cell });
                        this.grid[write][c] = cell;
                        this.grid[read][c]  = null;
                    }
                    write++;
                }
            }
        }
        return moves;
    }

    /** Fill `null` cells at the top of each column with fresh random tiles. */
    public fillEmpty(): SpawnedTile[] {
        const spawned: SpawnedTile[] = [];

        for (let c = 0; c < this.cols; c++) {
            let emptyCount = 0;
            for (let r = this.rows - 1; r >= 0; r--) {
                if (this.grid[r][c] === null) emptyCount++;
                else break;
            }

            for (let i = 0; i < emptyCount; i++) {
                const row  = this.rows - emptyCount + i;
                const cell: CellData = { color: this.randomColor(), superType: SuperTileType.None };
                this.grid[row][c] = cell;
                spawned.push({ position: { row, col: c }, cell, fallDistance: emptyCount - i });
            }
        }
        return spawned;
    }

    /** Fisher–Yates shuffle of every non‑null cell. */
    public shuffle(): void {
        const cells: CellData[] = [];
        for (let r = 0; r < this.rows; r++)
            for (let c = 0; c < this.cols; c++)
                if (this.grid[r][c]) cells.push(this.grid[r][c]!);

        for (let i = cells.length - 1; i > 0; i--) {
            const j = Math.floor(Math.random() * (i + 1));
            [cells[i], cells[j]] = [cells[j], cells[i]];
        }

        let idx = 0;
        for (let r = 0; r < this.rows; r++)
            for (let c = 0; c < this.cols; c++)
                this.grid[r][c] = cells[idx++] ?? null;
    }

    public swapTiles(a: GridPosition, b: GridPosition): void {
        const tmp = this.grid[a.row][a.col];
        this.grid[a.row][a.col] = this.grid[b.row][b.col];
        this.grid[b.row][b.col] = tmp;
    }

    // ── Area queries (used by SuperTileStrategy) ──────────

    public positionsInRow(row: number): GridPosition[] {
        const out: GridPosition[] = [];
        for (let c = 0; c < this.cols; c++)
            if (this.grid[row][c] !== null) out.push({ row, col: c });
        return out;
    }

    public positionsInColumn(col: number): GridPosition[] {
        const out: GridPosition[] = [];
        for (let r = 0; r < this.rows; r++)
            if (this.grid[r][col] !== null) out.push({ row: r, col });
        return out;
    }

    public positionsInRadius(centerRow: number, centerCol: number, radius: number): GridPosition[] {
        const out: GridPosition[] = [];
        for (let r = centerRow - radius; r <= centerRow + radius; r++)
            for (let c = centerCol - radius; c <= centerCol + radius; c++)
                if (r >= 0 && r < this.rows && c >= 0 && c < this.cols && this.grid[r][c] !== null)
                    out.push({ row: r, col: c });
        return out;
    }

    public allNonNullPositions(): GridPosition[] {
        const out: GridPosition[] = [];
        for (let r = 0; r < this.rows; r++)
            for (let c = 0; c < this.cols; c++)
                if (this.grid[r][c] !== null) out.push({ row: r, col: c });
        return out;
    }

    // ── Private ───────────────────────────────────────────

    private createEmpty(): (CellData | null)[][] {
        return Array.from({ length: this.rows }, () => new Array<CellData | null>(this.cols).fill(null));
    }

    private fillInitial(): void {
        for (let r = 0; r < this.rows; r++)
            for (let c = 0; c < this.cols; c++)
                this.grid[r][c] = { color: this.randomColor(), superType: SuperTileType.None };
    }

    private randomColor(): TileColor {
        return Math.floor(Math.random() * TILE_COLOR_COUNT) as TileColor;
    }
}
